// // This module splits a 16-bit input into two 8-bit outputs. The lower 8 bits are assigned to out_hi, and the higher 8 bits are taken from the most significant portion of the input.
module top_module(
    input wire [15:0] in,
    output wire [7:0] out_hi,
    output wire [7:0] out_lo);assign out_hi = in >> 8;
    assign out_lo = in[7:0];

endmodule
